function LxServerListImpl:OnQueryUpdateResult(bOk, ret, result, url)
    if self._isDisposed then
        return
    end

    if (not bOk or not result) then
        self:OnQueryUpdateFail(ret, result)
        return
    end

    local resultTbl = result

    self.updateResultTbl = result
    self:InitExclusiveMode(resultTbl.exclusive)
    self:InitUpdateConfig(resultTbl.updateConfig)

    LogWarn("current lua for product = " ..tostring(PRODUCT_G_VER))
    FireEvent(EventNames.ON_REFRESH_RETURN_PRODUCT)
    local callback = self.queryUpdateDataSuccessCallback
    self.queryUpdateDataSuccessCallback = nil
    if callback ~= nil then
        callback()
    end
end

-- 从服务器列表的updateConfig字段，设置更新目标信息
function LxServerListImpl:InitUpdateConfig(cfgTab)
    --local resKey = self.resKey or "default"
    local resKey = "default"
    if not cfgTab then
        self.webAppVer = self.localAppVer
        self.webResVer = self.localResVer
        return
    end

    local cfgItem = nil
    for k, v in ipairs(cfgTab) do
        if v.updateKey == resKey then
            cfgItem = v
            break
        end
    end
    if not cfgItem then
        for k, v in ipairs(cfgTab) do
            if v.updateKey == "default" then
                cfgItem = v
                break
            end
        end
        if not cfgItem then cfgItem = cfgTab[1] end
    end

    if cfgItem then
        self.webAppVer = cfgItem.clientVer
        self.webResVer = cfgItem.resVer
        self.webResUrl = cfgItem.resUrl
        self.webResUrl2 = cfgItem.resUrl2
        self.webApkUrl = cfgItem.apkUrl
        self.webApkUrl2 = cfgItem.apkUrl2
        self.webIosUrl = cfgItem.iosUrl
        self.webIosUrl2 = cfgItem.iosUrl2
    else
        self.webAppVer = self.defaultAppVersion
        self.webResVer = self.defaultPackageVersion
    end

end

function LxServerListImpl:InitExclusiveMode(exclusiveMap)
    self.isExclusiveMode = false

    if not CS.IsUnityEdit() then
        PRODUCT_G_VER = 0
    else
        if PRODUCT_G_VER ~= 0 then
            gLGameTable:ClearBeforeConf()
            gLGameI18n:HotReload()
        end
    end

    if not exclusiveMap then
        return
    end

    local resVer = self.activePackageVersion
    local resVerCheck = tostring(resVer)

    local exclusiveList = {}
    for k,v in pairs(exclusiveMap) do
        if v.exclusive == resVerCheck then
            table.insert(exclusiveList, v)
        end
    end

    self.isExclusiveMode = #exclusiveList > 0
    if self.isExclusiveMode then
        if CS.IsOSIos() or CS.IsOSAndroid() or CS.IsWebGL() or CS.IsOSOpenHarmony() then
            table.sort(exclusiveList, function (sA, sB) return sA.orders > sB.orders end)
            local serverData = exclusiveList[1]
            local exclusive_res = serverData.exclusive_res or ""
            if exclusive_res ~= "1" then
                if LGameSettings.platformRegion == LRegionConst.HMT or LGameSettings.platformRegion == LRegionConst.AMERICA then
                    PRODUCT_G_VER = 2
                else
                    PRODUCT_G_VER = 1
                end
            else
                PRODUCT_G_VER = 0
            end

            if PRODUCT_G_VER ~= 0 then
                gLGameTable:ClearBeforeConf()
                gLGameI18n:HotReload()
            end
        end
    end
end


function LxServerListImpl:StartGetServerList(successCallback, failCallback)
    self.queryServerListSuccessCallback = successCallback
    self.queryServerListFailCallback = failCallback

    if self._serverListGetter then
        self._serverListGetter:Dispose()
    end
    self._serverListGetter = LServerUtil.GetServerListGetter()
    self._serverListGetter:SetResultCallback(function(...)
        self:OnServerListResult(...)
    end)

    self._serverListGetter:StartQueryAll()

    GF.StartWait(LxHttpHelper.GET_MODE_TIME, nil, function()
        GF.StopWait()
        self:OnServerListFail(CS.YXWebRet.Timeout, "timeout")
    end, true)
end

function LxServerListImpl:OnServerListFail(webRet, result)
    if self._serverListGetter then
        self._serverListGetter:Dispose()
        self._serverListGetter = nil
    end

    local callback = self.queryServerListFailCallback
    self.queryServerListFailCallback = nil
    if callback ~= nil then
        callback(webRet, result)
    end
end

function LxServerListImpl:OnServerListResult(bOk, ret,result,url)
    if self._isDisposed then
        return
    end

    GF.StopWait()

    if (not bOk or not result) then
        self:OnServerListFail(ret,result)
        return
    end

    if self._serverListGetter then
        self._serverListGetter:Dispose()
        self._serverListGetter = nil
    end

    self.gameServerData = result

    local callback = self.queryServerListSuccessCallback
    self.queryServerListSuccessCallback = nil
    if callback ~= nil then
        callback()
    end
end
