function LxServerListImpl:GetVersionStr()
    local verStr = string.format("v1.0@%s_%s_%s", LNativeHelper.GetVersionName(), self.activeAppVersion, self.activePackageVersion)
    return verStr
end

function LxServerListImpl:GetVersionPID()
    local packageId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or "0"
    local verStr = string.format("v1.0@%s_%s_%s_%s", LNativeHelper.GetVersionName(), self.activeAppVersion, self.activePackageVersion, packageId)
    return verStr
end

